import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.Test;

class SketchEvidencePolicyTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final String POLICY_CLASS = "org.eclipse.rdf4j.sail.lmdb.sketch.SketchEvidencePolicy";
	private final List<SketchBasedJoinEstimator> estimators = new ArrayList<>();

	@AfterEach
	void closeEstimators() {
		for (SketchBasedJoinEstimator estimator : estimators) {
			estimator.close();
		}
	}

	@Test
	void snapshotOnlyDoesNotConsultLearnedOrLiveEvidence() throws Exception {
		SketchBasedJoinEstimator estimator = estimator();
		JoinStatsProvider learned = learnedEstimate(0.01d, 4_096L);
		AtomicInteger liveCalls = new AtomicInteger();
		estimator.setLearnedStatsProvider(learned);
		estimator.setPatternFilterSamplingEstimator(samplingEstimate(liveCalls, 0.95d, 4_096L));

		EvaluationStatistics.FilterPassEstimate estimate;
		try (QueryOptimizationScope ignored = beginScope(estimator, "SNAPSHOT_ONLY")) {
			estimate = estimator.estimateFilterPass(filter());
		}

		verifyNoInteractions(learned);
		assertEquals(0, liveCalls.get());
		assertTrue(estimate.getSource() == EvaluationStatistics.FilterPassEstimate.Source.HEURISTIC
				|| estimate.getSource() == EvaluationStatistics.FilterPassEstimate.Source.UNKNOWN,
				"Snapshot-only may use a supported heuristic, but must not use learned or sampled evidence");
	}

	@Test
	void adaptiveSkipsLiveSamplingWhenLearnedConfidenceIsHigh() throws Exception {
		SketchBasedJoinEstimator estimator = estimator();
		AtomicInteger liveCalls = new AtomicInteger();
		estimator.setLearnedStatsProvider(learnedEstimate(0.20d, 4_096L));
		estimator.setPatternFilterSamplingEstimator(samplingEstimate(liveCalls, 0.95d, 4_096L));

		EvaluationStatistics.FilterPassEstimate estimate;
		try (QueryOptimizationScope ignored = beginScope(estimator, "ADAPTIVE")) {
			estimate = estimator.estimateFilterPass(filter());
		}

		assertEquals(0, liveCalls.get());
		assertEquals(EvaluationStatistics.FilterPassEstimate.Source.LEARNED_FILTER, estimate.getSource());
		assertTrue(estimate.getConfidenceScore() >= 0.60d);
	}

	@Test
	void adaptiveSamplesWhenBestNonIoConfidenceIsBelowThreshold() throws Exception {
		SketchBasedJoinEstimator estimator = estimator();
		AtomicInteger liveCalls = new AtomicInteger();
		estimator.setLearnedStatsProvider(learnedEstimate(0.20d, 1L));
		estimator.setPatternFilterSamplingEstimator(samplingEstimate(liveCalls, 0.80d, 4_096L));

		EvaluationStatistics.FilterPassEstimate estimate;
		try (QueryOptimizationScope ignored = beginScope(estimator, "ADAPTIVE")) {
			estimate = estimator.estimateFilterPass(filter());
		}

		assertEquals(1, liveCalls.get());
		assertEquals(EvaluationStatistics.FilterPassEstimate.Source.SAMPLED, estimate.getSource());
		assertEquals(0.80d, estimate.getPassRatio(), 0.0d);
	}

	private SketchBasedJoinEstimator estimator() {
		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(new StubSketchStatementSource(),
				SketchBasedJoinEstimator.Config.defaults()
						.withSketchStrategy(SketchBasedJoinEstimator.SketchStrategy.COUNT_MIN_DUAL)
						.withRefreshSleepMillis(5L));
		estimators.add(estimator);
		return estimator;
	}

	private static JoinStatsProvider learnedEstimate(double ratio, long observations) {
		JoinStatsProvider provider = mock(JoinStatsProvider.class);
		when(provider.getFilterPassRatio(any(), anyString())).thenReturn(ratio);
		when(provider.getFilterObservationCount(any(), anyString())).thenReturn(observations);
		return provider;
	}

	private static PatternFilterSamplingEstimator samplingEstimate(AtomicInteger calls, double ratio,
			long observations) {
		return new PatternFilterSamplingEstimator() {
			@Override
			public double estimateFilterPassRatio(Filter filter, StatementPattern pattern) {
				return estimateFilterPass(filter, pattern).passRatio();
			}

			@Override
			public PatternFilterSampleEstimate estimateFilterPass(Filter filter, StatementPattern pattern) {
				calls.incrementAndGet();
				return new PatternFilterSampleEstimate(ratio, observations);
			}
		};
	}

	@SuppressWarnings({ "rawtypes", "unchecked" })
	private static QueryOptimizationScope beginScope(SketchBasedJoinEstimator estimator, String policyName)
			throws Exception {
		Class<? extends Enum> policyType = (Class<? extends Enum>) Class.forName(POLICY_CLASS).asSubclass(Enum.class);
		Object policy = Enum.valueOf(policyType, policyName);
		Method begin = SketchBasedJoinEstimator.class.getDeclaredMethod("beginQueryOptimizationScope", policyType);
		begin.setAccessible(true);
		return (QueryOptimizationScope) begin.invoke(estimator, policy);
	}

	private static Filter filter() {
		IRI predicate = VF.createIRI("urn:evidence:predicate");
		StatementPattern pattern = new StatementPattern(Var.of("s"), Var.of("p", predicate), Var.of("o"));
		return new Filter(pattern,
				new Compare(Var.of("o"), new ValueConstant(VF.createIRI("urn:evidence:object")), Compare.CompareOp.EQ));
	}
}
